/**
 * Represents the items which the [`data`](components/scheduler/api/schedulerprops#toc-data) property accepts.
 * The `data` has no strict type. However, to visualize it correctly,
 * use it in combination with the [`modelFields`](components/scheduler/api/schedulerprops#toc-modelfields) property.
 * For more information, refer to the article on
 * [binding the Scheduler to data](components/scheduler/data-binding).
 */
export type DataItem = any;
